```class Solution {
public:
    int maximumCostSubstring(string s, string chars, vector<int>& vals) {
        int res = 0, cur = 0;
        unordered_map<char, int> mp;
        for (int i = 0; i < chars.size(); i++) {
            mp[chars[i]] = vals[i];
        }
        for (char c : s) {
            cur += mp.count(c) ? mp[c] : c - 'a' + 1;
            res = max(res, cur);
            cur = max(cur, 0);
        }
        return res;
    }
};```
